javascript:(()=>{const u=location.href,t=document.title||"",toast=(m,k)=>{try{const d=document.createElement("div");d.textContent="bm: "+m;d.style.cssText="position:fixed;z-index:2147483647;right:16px;bottom:16px;padding:8px 12px;border-radius:6px;font:13px/1.3 system-ui;color:#fff;background:"+(k?"#10b981":"#ef4444")+";box-shadow:0 4px 12px rgba(0,0,0,.18);pointer-events:none";document.body.appendChild(d);setTimeout(()=>d.remove(),1600)}catch(e){}};fetch("http://localhost:9876/add",{method:"POST",mode:"no-cors",headers:{"Content-Type":"application/json"},body:JSON.stringify({url:u,title:t})}).then(()=>toast("Saved",true),()=>{toast("Failed — opening fallback popup",false);const q="url="+encodeURIComponent(u)+"&title="+encodeURIComponent(t);window.open("http://localhost:9876/add?"+q,"_blank","width=320,height=160")})})();
